# app.py
import os, re, time, hmac, hashlib, sqlite3, unicodedata, secrets
from collections import defaultdict, deque
from contextlib import contextmanager
from html import escape
from typing import Any

import bcrypt
from fastapi import FastAPI, Request, HTTPException
from fastapi.responses import JSONResponse
from email_validator import validate_email, EmailNotValidError

app = FastAPI()

DB_PATH = os.getenv("DB_PATH", "users.db")
APP_SECRET = os.getenv("APP_SECRET", secrets.token_urlsafe(32)).encode()
ALLOWED_ORIGINS = {
    o.strip().rstrip("/")
    for o in os.getenv("ALLOWED_ORIGINS", "http://localhost:8000").split(",")
}

USERNAME_RE = re.compile(r"^[a-z0-9][a-z0-9._-]{2,31}$")
EMAIL_MAX_LEN = 254
USERNAME_MIN_LEN = 3
USERNAME_MAX_LEN = 32
DISPLAY_NAME_MAX_LEN = 80
PASSWORD_MIN_LEN = 12
PASSWORD_MAX_LEN = 128

RESERVED_USERNAMES = {
    "admin", "administrator", "root", "system", "support", "help", "security",
    "moderator", "mod", "staff", "api", "www", "mail", "postmaster", "abuse",
    "null", "undefined", "anonymous", "owner", "official"
}

DISPOSABLE_DOMAINS = {
    "10minutemail.com", "guerrillamail.com", "mailinator.com", "tempmail.com",
    "throwawaymail.com", "yopmail.com", "trashmail.com", "getnada.com"
}

OFFENSIVE_TERMS = {
    # Keep this list maintained externally in real systems.
    "fuck", "shit", "bitch", "cunt", "nigger", "faggot"
}

_rate_limits: dict[str, deque[float]] = defaultdict(deque)


@contextmanager
def db():
    conn = sqlite3.connect(DB_PATH, isolation_level="IMMEDIATE", timeout=5)
    conn.row_factory = sqlite3.Row
    try:
        yield conn
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


def init_db():
    with db() as conn:
        conn.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT NOT NULL UNIQUE,
            email_lookup TEXT NOT NULL UNIQUE,
            username TEXT NOT NULL UNIQUE,
            username_lookup TEXT NOT NULL UNIQUE,
            display_name TEXT NOT NULL,
            password_hash TEXT NOT NULL,
            created_at INTEGER NOT NULL,
            email_verified INTEGER NOT NULL DEFAULT 0
        )
        """)
        conn.execute("CREATE INDEX IF NOT EXISTS idx_users_email_lookup ON users(email_lookup)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_users_username_lookup ON users(username_lookup)")


init_db()


def error(field: str, code: str, message: str) -> dict[str, str]:
    return {"field": field, "code": code, "message": message}


def normalize_unicode(value: str) -> str:
    return unicodedata.normalize("NFKC", value)


def contains_control_or_invisible(value: str) -> bool:
    for ch in value:
        cat = unicodedata.category(ch)
        if cat.startswith("C"):
            return True
    return False


def has_mixed_scripts(value: str) -> bool:
    scripts = set()
    for ch in value:
        if ch.isascii() or not ch.isalpha():
            continue
        name = unicodedata.name(ch, "")
        for script in ("LATIN", "CYRILLIC", "GREEK", "HEBREW", "ARABIC"):
            if script in name:
                scripts.add(script)
    return len(scripts) > 1


def hmac_lookup(value: str) -> str:
    return hmac.new(APP_SECRET, value.encode(), hashlib.sha256).hexdigest()


def sanitize_display_name(value: str) -> str:
    value = normalize_unicode(value).strip()
    value = re.sub(r"\s+", " ", value)
    return escape(value, quote=True)


def is_password_breached(password: str) -> bool:
    """
    Production version should call HaveIBeenPwned k-anonymity API:
    SHA1(password), send first 5 chars, compare suffix timing-safely.
    This local denylist prevents obvious known-bad passwords without network IO.
    """
    common = {
        "password", "password123", "123456789", "qwerty123",
        "letmein123", "adminadmin", "iloveyou123"
    }
    folded = password.casefold()
    return any(hmac.compare_digest(folded, p) for p in common)


def rate_limit_or_429(key: str, limit: int, window_seconds: int):
    now = time.time()
    bucket = _rate_limits[key]

    while bucket and bucket[0] <= now - window_seconds:
        bucket.popleft()

    if len(bucket) >= limit:
        raise HTTPException(
            status_code=429,
            detail={
                "error": "rate_limited",
                "message": "Too many registration attempts. Try again later.",
                "retry_after_seconds": int(window_seconds - (now - bucket[0])),
            },
        )

    bucket.append(now)


def validate_origin(request: Request):
    origin = request.headers.get("origin")
    if origin and origin.rstrip("/") not in ALLOWED_ORIGINS:
        raise HTTPException(status_code=403, detail={"error": "csrf_origin_rejected"})

    if request.cookies:
        csrf_cookie = request.cookies.get("csrf_token")
        csrf_header = request.headers.get("x-csrf-token")
        if not csrf_cookie or not csrf_header or not hmac.compare_digest(csrf_cookie, csrf_header):
            raise HTTPException(status_code=403, detail={"error": "csrf_token_invalid"})


def validate_payload(payload: dict[str, Any]) -> tuple[dict[str, str], list[dict[str, str]]]:
    errors: list[dict[str, str]] = []
    out: dict[str, str] = {}

    allowed = {"email", "username", "password", "display_name"}
    for key in payload:
        if key not in allowed:
            errors.append(error(key, "unknown_field", "Unknown field is not allowed."))

    for key in allowed:
        if key not in payload:
            errors.append(error(key, "required", "This field is required."))
        elif not isinstance(payload[key], str):
            errors.append(error(key, "invalid_type", "This field must be a string."))

    if errors:
        return out, errors

    raw_email = normalize_unicode(payload["email"]).strip()
    raw_username = normalize_unicode(payload["username"]).strip()
    raw_password = payload["password"]
    raw_display = payload["display_name"]

    if len(raw_email) > EMAIL_MAX_LEN:
        errors.append(error("email", "too_long", "Email must be at most 254 characters."))
    if contains_control_or_invisible(raw_email):
        errors.append(error("email", "invalid_characters", "Email contains invalid characters."))

    try:
        checked = validate_email(
            raw_email,
            check_deliverability=True,
            allow_smtputf8=False,
            allow_empty_local=False,
        )
        email = checked.normalized.casefold()
        domain = checked.domain.casefold().rstrip(".")
        if domain in DISPOSABLE_DOMAINS:
            errors.append(error("email", "disposable_domain", "Disposable email domains are not allowed."))
        if "." not in domain:
            errors.append(error("email", "invalid_domain", "Email domain must be fully qualified."))
        out["email"] = email
        out["email_lookup"] = hmac_lookup(email)
    except EmailNotValidError:
        errors.append(error("email", "invalid_format", "Email address is not valid."))

    username = raw_username.casefold()
    if not USERNAME_MIN_LEN <= len(username) <= USERNAME_MAX_LEN:
        errors.append(error("username", "length", "Username must be 3 to 32 characters."))
    if not USERNAME_RE.fullmatch(username):
        errors.append(error("username", "invalid_format", "Username may contain lowercase letters, numbers, dots, underscores, and hyphens."))
    if ".." in username or "__" in username or "--" in username:
        errors.append(error("username", "repeated_separator", "Username cannot contain repeated separators."))
    if username.endswith((".", "_", "-")):
        errors.append(error("username", "bad_suffix", "Username cannot end with a separator."))
    if username in RESERVED_USERNAMES:
        errors.append(error("username", "reserved", "Username is not available."))
    if any(term in username for term in OFFENSIVE_TERMS):
        errors.append(error("username", "offensive", "Username is not available."))
    if has_mixed_scripts(raw_username):
        errors.append(error("username", "mixed_scripts", "Username contains confusable characters."))

    out["username"] = username
    out["username_lookup"] = hmac_lookup(username)

    display = sanitize_display_name(raw_display)
    if not display:
        errors.append(error("display_name", "required", "Display name is required."))
    if len(display) > DISPLAY_NAME_MAX_LEN:
        errors.append(error("display_name", "too_long", "Display name must be at most 80 characters."))
    if contains_control_or_invisible(raw_display):
        errors.append(error("display_name", "invalid_characters", "Display name contains invalid characters."))
    if any(term in display.casefold() for term in OFFENSIVE_TERMS):
        errors.append(error("display_name", "offensive", "Display name is not allowed."))
    out["display_name"] = display

    password = raw_password
    if len(password) > PASSWORD_MAX_LEN:
        errors.append(error("password", "too_long", "Password must be at most 128 characters."))
    if len(password) < PASSWORD_MIN_LEN:
        errors.append(error("password", "too_short", "Password must be at least 12 characters."))
    if contains_control_or_invisible(password):
        errors.append(error("password", "invalid_characters", "Password contains invalid characters."))
    if not re.search(r"[a-z]", password):
        errors.append(error("password", "missing_lowercase", "Password must contain a lowercase letter."))
    if not re.search(r"[A-Z]", password):
        errors.append(error("password", "missing_uppercase", "Password must contain an uppercase letter."))
    if not re.search(r"\d", password):
        errors.append(error("password", "missing_digit", "Password must contain a digit."))
    if not re.search(r"[^A-Za-z0-9]", password):
        errors.append(error("password", "missing_symbol", "Password must contain a symbol."))
    if re.search(r"(.)\1{3,}", password):
        errors.append(error("password", "repeated_chars", "Password contains too many repeated characters."))
    if username and username in password.casefold():
        errors.append(error("password", "contains_username", "Password must not contain your username."))
    if out.get("email"):
        local = out["email"].split("@", 1)[0].casefold()
        if local and local in password.casefold():
            errors.append(error("password", "contains_email", "Password must not contain your email name."))
    if is_password_breached(password):
        errors.append(error("password", "breached", "Password is too common or known to be compromised."))

    out["password"] = password
    return out, errors


@app.post("/api/register")
async def register(request: Request):
    validate_origin(request)

    client_ip = request.client.host if request.client else "unknown"
    rate_limit_or_429(f"ip:{client_ip}", limit=10, window_seconds=3600)

    if request.headers.get("content-type", "").split(";")[0] != "application/json":
        raise HTTPException(status_code=415, detail={"error": "unsupported_media_type"})

    try:
        payload = await request.json()
    except Exception:
        raise HTTPException(status_code=400, detail={"error": "invalid_json"})

    if not isinstance(payload, dict):
        raise HTTPException(status_code=422, detail={"errors": [error("body", "invalid_type", "JSON body must be an object.")]})

    data, errors = validate_payload(payload)

    if data.get("email_lookup"):
        rate_limit_or_429(f"email:{data['email_lookup']}", limit=5, window_seconds=3600)

    if errors:
        return JSONResponse(status_code=422, content={"errors": errors})

    password_hash = bcrypt.hashpw(data["password"].encode(), bcrypt.gensalt(rounds=12)).decode()

    try:
        with db() as conn:
            conn.execute(
                """
                INSERT INTO users (
                    email, email_lookup, username, username_lookup,
                    display_name, password_hash, created_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    data["email"],
                    data["email_lookup"],
                    data["username"],
                    data["username_lookup"],
                    data["display_name"],
                    password_hash,
                    int(time.time()),
                ),
            )
    except sqlite3.IntegrityError:
        # Do not reveal whether the email exists. Username conflicts are user-facing;
        # email-only duplicates receive the same generic accepted response.
        with db() as conn:
            username_exists = conn.execute(
                "SELECT 1 FROM users WHERE username_lookup = ? LIMIT 1",
                (data["username_lookup"],),
            ).fetchone()

        if username_exists:
            return JSONResponse(
                status_code=409,
                content={
                    "errors": [
                        error("username", "unavailable", "Username is not available.")
                    ]
                },
            )

        return JSONResponse(
            status_code=202,
            content={
                "status": "accepted",
                "message": "If registration is eligible, the next step will be sent."
            },
        )

    return JSONResponse(
        status_code=201,
        content={
            "status": "created",
            "message": "Registration accepted. Verify your email to activate the account."
        },
    )
